class Solution:
    def findPrimePairs(self, n):
        def is_prime(v):
            if v < 2:
                return False
            d = 2
            while d * d <= v:
                if v % d == 0:
                    return False
                d += 1
            return True
        res = []
        for x in range(1, n + 1):
            y = n - x
            if y < x:
                break
            if is_prime(x) and is_prime(y):
                res.append([x, y])
        return res

