class Solution:
    def findPrimePairs(self, n):
        if n < 4:
            return []
        sieve = bytearray([1]) * (n + 1)
        sieve[0] = 0
        sieve[1] = 0
        i = 2
        while i * i <= n:
            if sieve[i]:
                for j in range(i * i, n + 1, i):
                    sieve[j] = 0
            i += 1
        res = []
        for x in range(2, n // 2 + 1):
            y = n - x
            if sieve[x] and sieve[y]:
                res.append([x, y])
        return res

