var findPrimePairs = function(n) {
    if (n < 4) return [];
    const sieve = new Uint8Array(n + 1).fill(1);
    sieve[0] = 0;
    sieve[1] = 0;
    for (let i = 2; i * i <= n; i++) {
        if (sieve[i]) {
            for (let j = i * i; j <= n; j += i) sieve[j] = 0;
        }
    }
    const res = [];
    for (let x = 2; x <= Math.floor(n / 2); x++) {
        const y = n - x;
        if (sieve[x] && sieve[y]) res.push([x, y]);
    }
    return res;
};
